		$table        = $wpdb->sitemeta;
		$column       = 'meta_key';
		$key_column   = 'meta_id';
		$value_column = 'meta_value';
	} else {
		$table        = $wpdb->options;
		$column       = 'option_name';
		$key_column   = 'option_id';
		$value_column = 'option_value';
	}

	// Escape the identifier for use in LIKE pattern
	$key = $wpdb->esc_like( $this->identifier ) . '_batch_%';

	// Build query with hardcoded table reference (selected above)
	if ( is_multisite() ) {
		$query = $wpdb->prepare(
			"SELECT *
			FROM {$wpdb->sitemeta}
			WHERE meta_key LIKE %s
			ORDER BY meta_id ASC
			LIMIT 1",
