/**
 * Enqueue scripts and localize with Pagarme global variables.
 *
 * @param string|array|null $scripts Script handle(s) to enqueue, or null to use defaults.
 * @param array             $deps    Array of script dependencies.
 *
 * @return void
 */
public function enqueue_scripts( $scripts = null, array $deps = [] ) {
    // Validate constant exists
    if ( ! defined( 'WCMP_JS_HANDLER_BASE_NAME' ) ) {
        return;
    }

    // Call parent enqueue
    parent::enqueue_scripts( $scripts, $deps );

    // Build script handle
    $script_handle = WCMP_JS_HANDLER_BASE_NAME . 'card';

    // Only localize if script is registered
    if ( wp_script_is( $script_handle, 'registered' ) ) {
        wp_localize_script(
            $script_handle,
            'PagarmeGlobalVars',
            self::getLocalizeScriptArgs()
        );
    }
}

